#!/bin/bash

# Function to update /etc/fstab
update_fstab() {
    if grep -q ' /dev/shm ' /etc/fstab; then
        sed -i '/ \/dev\/shm / s/\(defaults\|rw\|nodev\|nosuid\|noexec\)\+/\0,noexec/' /etc/fstab
    else
        echo "tmpfs /dev/shm tmpfs defaults,noexec 0 0" >> /etc/fstab
    fi
}

# Function to remount /dev/shm with noexec
remount_dev_shm() {
    mount -o remount,noexec /dev/shm
}

# Main execution
update_fstab
remount_dev_shm
